class Solution:
    def longestBalanced(self, s):
        n = len(s)
        best = 0
        for i in range(n):
            cnt = {'a': 0, 'b': 0, 'c': 0}
            for j in range(i, n):
                cnt[s[j]] += 1
                vals = [v for v in cnt.values() if v > 0]
                if len(set(vals)) == 1:
                    best = max(best, j - i + 1)
        return best

