var longestBalanced = function(s) {
    const n = s.length;
    const ca = new Array(n + 1).fill(0);
    const cb = new Array(n + 1).fill(0);
    const cc = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        ca[i+1] = ca[i] + (s[i] === 'a' ? 1 : 0);
        cb[i+1] = cb[i] + (s[i] === 'b' ? 1 : 0);
        cc[i+1] = cc[i] + (s[i] === 'c' ? 1 : 0);
    }
    let best = 0;
    let run = 0;
    for (let i = 0; i < n; i++) {
        if (i > 0 && s[i] === s[i-1]) run++; else run = 1;
        if (run > best) best = run;
    }
    const pair = (d, e) => {
        const first = new Map();
        let local = 0;
        for (let i = 0; i <= n; i++) {
            const key = d[i] + ',' + e[i];
            if (first.has(key)) {
                const span = i - first.get(key);
                if (span > local) local = span;
            } else {
                first.set(key, i);
            }
        }
        return local;
    };
    const diffAB = new Array(n + 1), diffAC = new Array(n + 1), diffBC = new Array(n + 1);
    for (let i = 0; i <= n; i++) { diffAB[i] = ca[i] - cb[i]; diffAC[i] = ca[i] - cc[i]; diffBC[i] = cb[i] - cc[i]; }
    best = Math.max(best, pair(diffAB, cc));
    best = Math.max(best, pair(diffAC, cb));
    best = Math.max(best, pair(diffBC, ca));
    best = Math.max(best, pair(diffAB, diffBC));
    return best;
};
